debounce function prevents a function from executing until a certain amount of time has passed without it being called again, helping to optimize performance for frequently triggered events.

function debounce(func, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example: Debouncing an input field change event
const inputElement = document.querySelector('#searchInput');
const searchAPI = (query) => {
  console.log('Searching for:', query);
  // This would typically make an API call
};

const debouncedSearch = debounce(searchAPI, 300);
inputElement.addEventListener('input', (event) => {
  debouncedSearch(event.target.value);
});
